    22→/**
    23→ * Maps detected taxonomy patterns to OpenAPI schemas.
    24→ *
    25→ * <p>This mapper generates OpenAPI schemas based on the taxonomy patterns detected
    26→ * by SchemaVisitor. Each pattern produces a different schema structure:
    27→ *
    28→ * <ul>
    29→ *   <li><b>Pattern A</b>: Inline StringSchema with enum values</li>
    30→ *   <li><b>Pattern B</b>: StringSchema with enum values (from codeValue or label)</li>
    31→ *   <li><b>Pattern C</b>: $ref to schema in components/schemas</li>
    32→ *   <li><b>Pattern D</b>: $ref to Coding schema in components/schemas</li>
    33→ * </ul>
    34→ *
    35→ * @see TaxonomyPattern
    36→ * @see TaxonomyInfo
    37→ */
    38→public class TaxonomyPatternMapper {
    39→
    40→  private final PropertyNameResolver nameResolver = new PropertyNameResolver();
    41→  private final MappingContext context;
    42→  private final TaxonomyInfo info;
    43→  private final Set<RestrictionInfo> restrictions;
    44→  private final String description;
    45→  private final String label;
    46→
    47→  private final boolean isArray;
    48→  private final boolean isRequired;
    49→
    50→  public TaxonomyPatternMapper(
    51→      MappingContext context,
    52→      TaxonomyInfo info,
    53→      Set<RestrictionInfo> restrictions,
    54→      String description,
    55→      String label) {
    56→    this.context = context;
    57→    this.info = info;
    58→    this.restrictions = restrictions;
    59→    this.description = description;
    60→    this.label = label;
    61→
    62→    YamlConfig config = context.getConfig();
    63→    this.isArray = restrictions != null &&
    64→        restrictions.stream().anyMatch(RestrictionInfo::impliesArray);
    65→    this.isRequired = config.isEnforceRequiredness() &&
    66→        restrictions != null && restrictions.stream().anyMatch(RestrictionInfo::impliesRequired);
    67→  }
    68→
    69→  public String getName() {
    70→    return info.propertyName();
    71→  }
    72→
    73→  public boolean isRequired() {
    74→    return isRequired;
    75→  }
    76→
    77→  /**
    78→   * Generates the OpenAPI schema based on the detected taxonomy pattern.
    79→   */
    80→  public Schema<?> getSchema() {
    81→    return switch (info.pattern()) {
    82→      case PATTERN_A -> mapPatternA();
    83→      case PATTERN_B -> mapPatternB();
    84→      case PATTERN_C -> mapPatternC();
    85→      case PATTERN_D -> mapPatternD();
    86→      case NONE -> throw new IllegalArgumentException(
    87→          "Cannot map NONE pattern to schema for property: " + info.propertyName());
    88→    };
    89→  }
    90→
    91→  /**
    92→   * Pattern A: Inline enumeration with untyped individuals.
    93→   * Generates StringSchema with enum values from individual labels.
    94→   */
    95→  private Schema<?> mapPatternA() {
    96→    List<String> enumValues = info.individuals().stream()
    97→        .map(ind -> OntologyUtil.getTitle(ind, context.getOntology()))
    98→        .toList();
    99→
   100→    StringSchema enumSchema = new StringSchema();
   101→    enumSchema.setDescription(description);
   102→    enumSchema.setEnum(enumValues);
   103→
   104→    return wrapInArrayIfNeeded(enumSchema);
   105→  }
   106→
   107→  /**
   108→   * Pattern B: Typed individuals with metadata.
   109→   * Generates StringSchema with enum values (uses codeValue if available, otherwise label).
   110→   */
   111→  private Schema<?> mapPatternB() {
   112→    List<String> enumValues = new ArrayList<>();
   113→
   114→    for (OWLNamedIndividual ind : info.individuals()) {
   115→      String indName = nameResolver.resolve(ind);
   116→      TaxonomyInfo.IndividualMetadata meta = info.metadata().get(indName);
   117→
   118→      // Use codeValue if available, otherwise use label
   119→      String codeValue = meta != null && meta.codeValue() != null
   120→          ? meta.codeValue()
   121→          : OntologyUtil.getTitle(ind, context.getOntology());
   122→      enumValues.add(codeValue);
   123→    }
   124→
   125→    StringSchema enumSchema = new StringSchema();
   126→    enumSchema.setDescription(description);
   127→    enumSchema.setEnum(enumValues);
   128→
   129→    return wrapInArrayIfNeeded(enumSchema);
   130→  }
   131→
   132→  /**
   133→   * Pattern C: Class-based taxonomy (extensible).
   134→   * Generates $ref to schema in components/schemas.
   135→   */
   136→  private Schema<?> mapPatternC() {
   137→    OWLClass targetClass = info.targetClass();
   138→    if (targetClass == null) {
   139→      throw new IllegalStateException("Pattern C requires a target class");
   140→    }
   141→
   142→    String schemaName = nameResolver.resolve(targetClass);
   143→
   144→    // Create or get the taxonomy schema in components/schemas
   145→    createTaxonomySchemaIfNeeded(schemaName, targetClass);
   146→
   147→    // Create reference to the taxonomy schema
   148→    Schema<?> refSchema = new Schema<>();
   149→    refSchema.set$ref("#/components/schemas/" + schemaName);
   150→
   151→    return wrapInArrayIfNeeded(refSchema);
   152→  }
   153→
   154→  /**
   155→   * Pattern D: SKOS taxonomy (FHIR-compatible).
   156→   * Generates $ref to Coding schema in components/schemas.
   157→   */
   158→  private Schema<?> mapPatternD() {
   159→    OWLClass targetClass = info.targetClass();
   160→    if (targetClass == null) {
   161→      throw new IllegalStateException("Pattern D requires a target class");
   162→    }
   163→
   164→    String schemaName = nameResolver.resolve(targetClass) + "Coding";
   165→
   166→    // Create or get the SKOS Coding schema
   167→    createSkosCodingSchemaIfNeeded(schemaName, targetClass);
   168→
   169→    // Create reference to the Coding schema
   170→    Schema<?> refSchema = new Schema<>();
   171→    refSchema.set$ref("#/components/schemas/" + schemaName);
   172→
   173→    return wrapInArrayIfNeeded(refSchema);
   174→  }
   175→
   176→  private Schema<?> wrapInArrayIfNeeded(Schema<?> itemSchema) {
   177→    if (isArray) {
   178→      ArraySchema arraySchema = new ArraySchema();
   179→      arraySchema.setName(info.propertyName());
   180→      arraySchema.setTitle(label);
   181→
   182→      // Apply cardinality restrictions
   183→      if (restrictions != null) {
   184→        for (RestrictionInfo restriction : restrictions) {
   185→          restriction.applyToArraySchema(arraySchema);
   186→        }
   187→      }
   188→
   189→      arraySchema.setItems(itemSchema);
   190→      return arraySchema;
   191→    } else {
   192→      itemSchema.setName(info.propertyName());
   193→      itemSchema.setTitle(label);
   194→      return itemSchema;
   195→    }
   196→  }
   197→
   198→  /**
   199→   * Creates the taxonomy schema in components/schemas for Pattern C.
   200→   */
   201→  private void createTaxonomySchemaIfNeeded(String schemaName, OWLClass targetClass) {
   202→    Map<String, Schema<?>> schemas = context.getSchemaByRef();
   203→    if (schemas.containsKey(schemaName)) {
   204→      return;
   205→    }
   206→
   207→    OWLOntology ontology = context.getOntology();
   208→
   209→    ObjectSchema taxonomySchema = new ObjectSchema();
   210→    taxonomySchema.setName(schemaName);
   211→    taxonomySchema.setTitle(OntologyUtil.getTitle(targetClass, ontology));
   212→    taxonomySchema.setDescription(OntologyUtil.getDescription(targetClass, ontology));
   213→
   214→    // Add code property with enum values
   215→    List<String> enumValues = info.individuals().stream()
   216→        .map(ind -> {
   217→          // Try to get codeValue annotation, fallback to label
   218→          String codeVal = getCodeValue(ind, ontology);
   219→          return codeVal != null ? codeVal : OntologyUtil.getTitle(ind, ontology);
   220→        })
   221→        .toList();
   222→
   223→    StringSchema codeSchema = new StringSchema();
   224→    codeSchema.setDescription("The code value");
   225→    if (!enumValues.isEmpty()) {
   226→      codeSchema.setEnum(enumValues);
   227→    }
   228→    taxonomySchema.addProperty("code", codeSchema);
   229→
   230→    // Add displayName property
   231→    StringSchema displayNameSchema = new StringSchema();
   232→    displayNameSchema.setDescription("Human-readable display name");
   233→    taxonomySchema.addProperty("displayName", displayNameSchema);
   234→
   235→    schemas.put(schemaName, taxonomySchema);
   236→  }
   237→
   238→  /**
   239→   * Creates the SKOS Coding schema in components/schemas for Pattern D.
   240→   */
   241→  private void createSkosCodingSchemaIfNeeded(String schemaName, OWLClass targetClass) {
   242→    Map<String, Schema<?>> schemas = context.getSchemaByRef();
   243→    if (schemas.containsKey(schemaName)) {
   244→      return;
   245→    }
   246→
   247→    OWLOntology ontology = context.getOntology();
   248→
   249→    ObjectSchema codingSchema = new ObjectSchema();
   250→    codingSchema.setName(schemaName);
   251→    codingSchema.setTitle(OntologyUtil.getTitle(targetClass, ontology) + " Coding");
   252→    codingSchema.setDescription("SKOS-based coding for " +
   253→        OntologyUtil.getDescription(targetClass, ontology));
   254→
   255→    // Add system property (constant for the CodeSystem)
   256→    StringSchema systemSchema = new StringSchema();
   257→    systemSchema.setDescription("The CodeSystem URL");
   258→    codingSchema.addProperty("system", systemSchema);
   259→
   260→    // Add code property
   261→    StringSchema codeSchema = new StringSchema();
   262→    codeSchema.setDescription("The code value (skos:notation)");
   263→    codingSchema.addProperty("code", codeSchema);
   264→
   265→    // Add display property
   266→    StringSchema displaySchema = new StringSchema();
   267→    displaySchema.setDescription("Human-readable display (skos:prefLabel)");
   268→    codingSchema.addProperty("display", displaySchema);
   269→
   270→    // Add required fields
   271→    codingSchema.addRequiredItem("code");
   272→
   273→    schemas.put(schemaName, codingSchema);
   274→  }
   275→
   276→  private String getCodeValue(OWLNamedIndividual individual, OWLOntology ontology) {
   277→    // Look for codeValue or skos:notation annotation
   278→    return EntitySearcher.getAnnotations(individual, ontology)
   279→        .filter(ann -> {
   280→          String propName = ann.getProperty().getIRI().getShortForm();
   281→          return propName.equals("codeValue") || propName.equals("notation");
   282→        })
   283→        .findFirst()
   284→        .flatMap(ann -> ann.getValue().asLiteral())
   285→        .map(lit -> lit.getLiteral())
   286→        .orElse(null);
   287→  }
   288→
   289→}
