    52→/**
    53→ * Visitor interface to inspect OWL Class Restrictions.
    54→ *
    55→ * <p>This visitor traverses an OWL class hierarchy and collects type-safe restriction information
    56→ * for both object properties and data properties. It implements the Visitor pattern via
    57→ * {@link OWLObjectVisitor} to handle different types of OWL class expressions.
    58→ *
    59→ * <h2>Usage</h2>
    60→ * <pre>{@code
    61→ * OWLClass myClass = ...;
    62→ * OWLOntology ontology = ...;
    63→ * OWLClass owlThing = dataFactory.getOWLThing();
    64→ *
    65→ * SchemaVisitor visitor = new SchemaVisitor(myClass, ontology, owlThing, "", false);
    66→ * myClass.accept(visitor);
    67→ *
    68→ * // Access collected restrictions
    69→ * Map<String, List<RestrictionInfo>> restrictions = visitor.getRestrictions();
    70→ * Set<String> objectProperties = visitor.getObjectPropertyNames();
    71→ * }</pre>
    72→ *
    73→ * <h2>Constructor Parameters</h2>
    74→ * <ul>
    75→ *   <li><b>visitedClass</b>: The OWL class to analyze for restrictions</li>
    76→ *   <li><b>onto</b>: The ontology containing the class and its axioms</li>
    77→ *   <li><b>owlThing</b>: Reference to owl:Thing for filtering (restrictions to owl:Thing are ignored)</li>
    78→ *   <li><b>propertyName</b>: Initial property name context (typically empty "")</li>
    79→ *   <li><b>range</b>: Whether analyzing ranges (typically false for initial call)</li>
    80→ * </ul>
    81→ *
    82→ * <h2>Visitor Traversal Behavior</h2>
    83→ * <p>The visitor recursively processes class hierarchies:
    84→ * <ul>
    85→ *   <li>When visiting a class, all {@link org.semanticweb.owlapi.model.OWLSubClassOfAxiom}s are followed</li>
    86→ *   <li>Cycle detection via {@code processedClasses} prevents infinite recursion in circular hierarchies</li>
    87→ *   <li>Complex class expressions (unions, intersections) are recursively traversed via {@code accept()}</li>
    88→ *   <li>Property restrictions are collected and stored as type-safe {@link RestrictionInfo} objects</li>
    89→ * </ul>
    90→ *
    91→ * <h2>Thread Safety</h2>
    92→ * <p>This class is <b>not thread-safe</b>. Each visitor instance maintains mutable state during
    93→ * traversal and should not be shared between threads or reused for multiple traversals.
    94→ *
    95→ * @see RestrictionInfo
    96→ * @see PropertyNameResolver
    97→ */
    98→public class SchemaVisitor implements OWLObjectVisitor {
    99→
   100→  Logger logger = Logger.getLogger(SchemaVisitor.class.getName());
   101→
   102→  private final PropertyNameResolver nameResolver = new PropertyNameResolver();
   103→  private final Set<OWLClass> processedClasses;
   104→  private final OWLClass cls;
   105→  private final OWLOntology onto;
   106→  String propertyName;
   107→  OWLClass owlThing;
   108→  Boolean range;
   109→
   110→
   111→  // Type-safe storage (private with unmodifiable getters)
   112→  private final Map<String, Set<RestrictionInfo>> restrictions = new HashMap<>();
   113→  private final Multimap<String, OWLClass> objectPropertyRanges = HashMultimap.create();
   114→  private final Multimap<String, OWLDatatype> dataPropertyRanges = HashMultimap.create();
   115→
   116→  // Property name tracking (minimal - just names, not full OWL objects)
   117→  private final Set<String> objectPropertyNames = new HashSet<>();
   118→  private final Set<String> dataPropertyNames = new HashSet<>();
   119→
   120→  // Taxonomy pattern tracking
   121→  private final Map<String, TaxonomyInfo> taxonomyPatterns = new HashMap<>();
   122→
   123→  /**
   124→   * Creates a new SchemaVisitor to analyze OWL class restrictions.
   125→   *
   126→   * @param visitedClass the OWL class to analyze for restrictions
   127→   * @param onto         the ontology containing the class and its axioms
   128→   * @param owlThing     reference to owl:Thing (restrictions to owl:Thing are ignored as they add
   129→   *                     no information)
   130→   * @param propertyName initial property name context (typically empty "" for top-level analysis)
   131→   * @param range        whether this visitor is analyzing property ranges (typically false for
   132→   *                     initial call)
   133→   */
   134→  public SchemaVisitor(OWLClass visitedClass, OWLOntology onto, OWLClass owlThing,
   135→      String propertyName, Boolean range) {
   136→    processedClasses = new HashSet<>();
   137→    this.cls = visitedClass;
   138→    this.onto = onto;
   139→    this.propertyName = propertyName;
   140→    this.owlThing = owlThing;
   141→    this.range = range;
   142→  }
   143→
   144→  @Override
   145→  public void visit(OWLClass ce) {
   146→    if (!processedClasses.contains(ce)) {
   147→      processedClasses.add(ce);
   148→      for (OWLSubClassOfAxiom ax : onto.getSubClassAxiomsForSubClass(ce)) {
   149→        ax.getSuperClass().accept(this);
   150→      }
   151→    }
   152→  }
   153→
   154→  @Override
   155→  public void visit(OWLObjectSomeValuesFrom ce) {
   156→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   157→    for (OWLObjectProperty property : ce.getObjectPropertiesInSignature()) {
   158→      propertyName = cleanName(nameResolver.resolve(property));
   159→      objectPropertyNames.add(propertyName);
   160→      restrictions.computeIfAbsent(propertyName, k -> new LinkedHashSet<>())
   161→          .add(new RestrictionInfo.SomeValuesFrom(ce));
   162→
   163→      // Detect taxonomy patterns
   164→      detectTaxonomyPattern(propertyName, ce.getFiller());
   165→    }
   166→
   167→    if (ce.getFiller() instanceof OWLObjectUnionOf ||
   168→        ce.getFiller() instanceof OWLObjectIntersectionOf ||
   169→        ce.getFiller() instanceof OWLObjectOneOf) {
   170→      ce.getFiller().accept(this);
   171→    } else {
   172→      if (!ce.getFiller().asOWLClass().equals(owlThing)) {
   173→        objectPropertyRanges.put(propertyName, ce.getFiller().asOWLClass());
   174→      } else {
   175→        logger.fine("Ignoring owl:Thing range " + propertyName);
   176→      }
   177→    }
   178→    propertyName = "";
   179→  }
   180→
   181→  @Override
   182→  public void visit(OWLObjectAllValuesFrom ce) {
   183→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   184→    for (OWLObjectProperty property : ce.getObjectPropertiesInSignature()) {
   185→      propertyName = cleanName(nameResolver.resolve(property));
   186→      objectPropertyNames.add(propertyName);
   187→      restrictions.computeIfAbsent(propertyName, k -> new LinkedHashSet<>())
   188→          .add(new RestrictionInfo.AllValuesFrom(ce));
   189→
   190→      // Detect taxonomy patterns
   191→      detectTaxonomyPattern(propertyName, ce.getFiller());
   192→    }
   193→
   194→    if (ce.getFiller() instanceof OWLObjectUnionOf
   195→        || ce.getFiller() instanceof OWLObjectIntersectionOf
   196→        || ce.getFiller() instanceof OWLObjectOneOf) {
   197→      ce.getFiller().accept(this);
   198→    } else {
   199→      if (!ce.getFiller().asOWLClass().equals(owlThing)) {
   200→        objectPropertyRanges.put(propertyName, ce.getFiller().asOWLClass());
   201→      } else {
   202→        logger.fine("Ignoring owl:Thing range " + propertyName);
   203→      }
   204→    }
   205→    propertyName = "";
   206→  }
   207→
   208→  @Override
   209→  public void visit(OWLObjectUnionOf ce) {
   210→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   211→    setBooleanCombinationObjectProperties(ce, ce.getOperands(),
   212→        ce.getObjectPropertiesInSignature());
   213→  }
   214→
   215→  @Override
   216→  public void visit(OWLObjectIntersectionOf ce) {
   217→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   218→    setBooleanCombinationObjectProperties(ce, ce.getOperands(),
   219→        ce.getObjectPropertiesInSignature());
   220→  }
   221→
