   574→  private boolean hasDomainClass(OWLNamedIndividual individual) {
   575→    return EntitySearcher.getTypes(individual, onto)
   576→        .anyMatch(type -> type.isNamed() && !type.isOWLThing());
   577→  }
   578→
   579→  private OWLClass getDomainClass(OWLNamedIndividual individual) {
   580→    return EntitySearcher.getTypes(individual, onto)
   581→        .filter(type -> type.isNamed() && !type.isOWLThing())
   582→        .map(OWLClassExpression::asOWLClass)
   583→        .findFirst()
   584→        .orElse(null);
   585→  }
   586→
   587→  private String getAnnotationValue(OWLNamedIndividual individual, org.semanticweb.owlapi.model.IRI annotationIRI) {
   588→    return EntitySearcher.getAnnotations(individual, onto)
   589→        .filter(ann -> ann.getProperty().getIRI().equals(annotationIRI))
   590→        .findFirst()
   591→        .flatMap(ann -> ann.getValue().asLiteral())
   592→        .map(lit -> lit.getLiteral())
   593→        .orElse(null);
   594→  }
   595→
   596→  private boolean isSubClassOfSkosConcept(OWLClass cls) {
   597→    return EntitySearcher.getSuperClasses(cls, onto)
   598→        .anyMatch(superCls -> superCls.isNamed() &&
   599→            superCls.asOWLClass().getIRI().equals(OntologyConstants.SKOS_CONCEPT));
   600→  }
   601→
   602→  private boolean hasInSchemeRestriction(OWLClass cls) {
   603→    return onto.subClassAxiomsForSubClass(cls)
   604→        .map(ax -> ax.getSuperClass())
   605→        .anyMatch(superCls -> {
   606→          if (superCls instanceof org.semanticweb.owlapi.model.OWLObjectHasValue hasValue) {
   607→            return hasValue.getProperty().isNamed() &&
   608→                hasValue.getProperty().asOWLObjectProperty().getIRI().equals(OntologyConstants.SKOS_IN_SCHEME);
   609→          }
   610→          return false;
   611→        });
   612→  }
   613→
   614→  private boolean hasObjectPropertyRestrictions(OWLClass cls) {
   615→    return onto.subClassAxiomsForSubClass(cls)
   616→        .map(ax -> ax.getSuperClass())
   617→        .anyMatch(superCls -> !superCls.getObjectPropertiesInSignature().isEmpty());
   618→  }
   619→
   620→  private boolean hasSubclassHierarchy(OWLClass cls) {
   621→    return onto.classesInSignature()
   622→        .anyMatch(subCls -> EntitySearcher.getSuperClasses(subCls, onto)
   623→            .anyMatch(superCls -> superCls.isNamed() && superCls.asOWLClass().equals(cls)));
   624→  }
   625→
   626→  private org.semanticweb.owlapi.model.OWLIndividual findConceptScheme(OWLClass cls) {
   627→    // Look for skos:inScheme restriction value
   628→    return onto.subClassAxiomsForSubClass(cls)
   629→        .map(ax -> ax.getSuperClass())
   630→        .filter(superCls -> superCls instanceof org.semanticweb.owlapi.model.OWLObjectHasValue)
   631→        .map(superCls -> (org.semanticweb.owlapi.model.OWLObjectHasValue) superCls)
   632→        .filter(hasValue -> hasValue.getProperty().isNamed() &&
   633→            hasValue.getProperty().asOWLObjectProperty().getIRI().equals(OntologyConstants.SKOS_IN_SCHEME))
   634→        .map(hasValue -> hasValue.getFiller())
   635→        .findFirst()
   636→        .orElse(null);
   637→  }
   638→
   639→  private List<OWLNamedIndividual> findSkosConceptIndividuals(OWLClass cls) {
   640→    List<OWLNamedIndividual> result = new ArrayList<>();
   641→    // Find individuals that are instances of this class or have skos:inScheme pointing to the same scheme
   642→    EntitySearcher.getIndividuals(cls, onto)
   643→        .filter(ind -> ind instanceof OWLNamedIndividual)
   644→        .map(ind -> (OWLNamedIndividual) ind)
   645→        .forEach(result::add);
   646→    return result;
   647→  }
   648→
   649→  private List<OWLNamedIndividual> findClassIndividuals(OWLClass cls) {
   650→    List<OWLNamedIndividual> result = new ArrayList<>();
   651→    // Find all individuals of this class and its subclasses
   652→    EntitySearcher.getIndividuals(cls, onto)
   653→        .filter(ind -> ind instanceof OWLNamedIndividual)
   654→        .map(ind -> (OWLNamedIndividual) ind)
   655→        .forEach(result::add);
   656→
   657→    // Also check subclasses
   658→    onto.classesInSignature()
   659→        .filter(subCls -> EntitySearcher.getSuperClasses(subCls, onto)
   660→            .anyMatch(superCls -> superCls.isNamed() && superCls.asOWLClass().equals(cls)))
   661→        .forEach(subCls -> EntitySearcher.getIndividuals(subCls, onto)
   662→            .filter(ind -> ind instanceof OWLNamedIndividual)
   663→            .map(ind -> (OWLNamedIndividual) ind)
   664→            .forEach(result::add));
   665→
   666→    return result;
   667→  }
   668→}

